_GENERIC_ACKS = {
    "ack",
    "checked",
    "confirmed",
    "done",
    "good",
    "looks good",
    "n/a",
    "na",
    "ok",
    "verified",
    "yes",
}
_MIN_VERDICT_CHARS = 20
_MIN_VERDICT_WORDS = 4
_MIN_VERDICT_UNIQUE_WORDS = 3


